class Person:
    def __init__(self, name, age):
        self.name = name
        self.age = age

    def greet(self):
        print(f"Hi, I'm {self.name}, {self.age} years old")

p1 = Person("Tamil", 25)
p1.greet()  # Hi, I'm Tamil, 25 years old

# Parent class
class Animal:
    def __init__(self, name):
        self.name = name

    def speak(self):
        print(f"{self.name} makes a sound")

# Child class
class Dog(Animal):
    def speak(self):
        print(f"{self.name} says Woof!")

d = Dog("Rex")
d.speak()  # Rex says Woof!

class Student(Person):
    def __init__(self, name, age, year):
        super().__init__(name, age)  # Parent init
        self.year = year

    def welcome(self):
        print(f"Welcome {self.name}, year {self.year}")

class Numbers:
    def __iter__(self):
        self.n = 1
        return self

    def __next__(self):
        if self.n <= 5:
            x = self.n
            self.n += 1
            return x
        else:
            raise StopIteration

nums = Numbers()
for x in nums:
    print(x)  # 1, 2, 3, 4, 5

class Cat:
    def sound(self):
        print("Meow")

class Dog:
    def sound(self):
        print("Woof")

# Polymorphism in action
animals = [Cat(), Dog()]
for animal in animals:
    animal.sound()  # Each calls its own version

class Animal:
    def speak(self):
        print("Animal makes sound")

class Dog(Animal):
    def speak(self):
        print("Woof!")

class Cat(Animal):
    def speak(self):
        print("Meow!")

def make_sound(animal):
    animal.speak()

make_sound(Dog())  # Woof!
make_sound(Cat())  # Meow!

